import { NavLink } from "react-router-dom";
import { useAuth, hasRole } from "../AuthContext";

/** Item nav: hỗ trợ collapsed + icon đổi màu theo isActive */
function Item({ to, label, icon, collapsed }) {
    return (
        <NavLink
            to={to}
            className={({ isActive }) =>
                "flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-indigo-50 " +
                (isActive ? "bg-indigo-600 text-white hover:bg-indigo-600" : "text-slate-700")
            }
            title={collapsed ? label : undefined}
        >
            {({ isActive }) => (
                <>
          <span
              className={
                  "w-6 h-6 grid place-content-center rounded " +
                  (isActive ? "bg-indigo-600 text-white" : "bg-indigo-100 text-indigo-700")
              }
              aria-hidden
          >
            {icon}
          </span>
                    {!collapsed && <span className="text-sm truncate">{label}</span>}
                </>
            )}
        </NavLink>
    );
}

/** Sidebar có thể thu gọn (collapsed) và có onToggle để Layout điều khiển */
export default function Sidebar({ collapsed = false, onToggle = () => {} }) {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAcc = hasRole(user, "ACCOUNTANT");

    // Xây dựng menu theo vai trò (rõ ràng, tránh lọt quyền hiển thị)
    const items = [
        { key: "dashboard", to: "/dashboard", label: "Tổng quan", icon: "🏠", show: true },

        // SALES & ADMIN
        { key: "customers", to: "/customers", label: "Khách hàng", icon: "👥", show: isAdmin || isSales },

        // ADMIN, SALES, ACCOUNTANT
        { key: "contracts", to: "/contracts", label: "Hợp đồng", icon: "📑", show: isAdmin || isSales || isAcc },

        // ADMIN, ACCOUNTANT
        { key: "payments", to: "/payments", label: "Thanh toán", icon: "💳", show: isAdmin || isAcc },

        // ADMIN, SALES
        { key: "events", to: "/events", label: "Sự kiện", icon: "📅", show: isAdmin || isSales },

        // ADMIN only
        { key: "users", to: "/users", label: "Người dùng", icon: "🛠", show: isAdmin },

        // ADMIN, ACCOUNTANT
        { key: "reports", to: "/reports", label: "Báo cáo", icon: "📈", show: isAdmin || isAcc },
    ];

    // Nếu là ACCOUNTANT, chỉ giữ đúng các mục dành cho ACC
    // (dashboard, contracts, payments, reports)
    const prunedItems = isAcc && !isAdmin
        ? items.filter(i => ["dashboard", "contracts", "payments", "reports"].includes(i.key))
        : items.filter(i => i.show);

    return (
        <aside
            className={
                "bg-white/80 backdrop-blur shadow-xl border-r border-indigo-100 hidden lg:flex flex-col " +
                (collapsed ? "w-16" : "w-72")
            }
        >
            {/* Header + nút toggle */}
            <div
                className={
                    "p-4 border-b border-indigo-100 flex items-center " +
                    (collapsed ? "justify-center" : "justify-between")
                }
            >
                <div className={"flex items-center gap-3 " + (collapsed ? "hidden" : "")}>
                    <div className="w-10 h-10 rounded-xl bg-indigo-600 text-white grid place-content-center font-bold">
                        CT
                    </div>
                    <div className="font-bold text-slate-900">Quản lý KH & Hợp đồng</div>
                </div>

                <button
                    onClick={onToggle}
                    aria-label={collapsed ? "Mở rộng thanh bên" : "Thu gọn thanh bên"}
                    className="ml-auto inline-flex items-center justify-center h-9 w-9 rounded-lg border border-indigo-100 bg-white hover:bg-indigo-50 text-slate-600"
                    title={collapsed ? "Mở rộng" : "Thu gọn"}
                >
                    {/* mũi tên: quay khi đang mở */}
                    <span className={"transition-transform " + (collapsed ? "" : "rotate-180")}>❮</span>
                </button>
            </div>

            {/* Nav */}
            <nav className={"flex-1 overflow-auto p-3 space-y-2 " + (collapsed ? "px-2" : "px-3")}>
                {prunedItems.map((it) => (
                    <Item key={it.key} to={it.to} label={it.label} icon={it.icon} collapsed={collapsed} />
                ))}
            </nav>
        </aside>
    );
}
